+    #[must_use]
+    pub fn gracefully_cancelled(&self) -> bool {
+        !self.completed && self.cancelled_at_checkpoint
+    }
+
+    /// Returns true if the handler completed despite cancellation request.
+    #[must_use]
+    pub fn completed_despite_cancel(&self) -> bool {
+        self.completed
+    }
